// Parse multipart form data and extract files + questions mapping
const crypto = require('crypto');
const items = $input.all();
const firstItem = items[0];

// Get questions JSON from form data (try multiple locations)
let questionsRaw = firstItem.json?.questions || firstItem.json?.body?.questions || firstItem.json?.query?.questions;

// Debug logging
console.log('First item keys:', Object.keys(firstItem.json || {}));
console.log('Questions raw value:', questionsRaw);
if (firstItem.binary) {
    console.log('Binary field keys:', Object.keys(firstItem.binary));
}

if (!questionsRaw) {
    throw new Error('Missing "questions" parameter. Expected JSON array: [{"question_id":"q1","files":["file1.pdf"]}]. Received structure: ' + JSON.stringify(Object.keys(firstItem.json || {})));
}

let questions;
try {
    // Sanitize: strip control characters (newlines, carriage returns, tabs) that
    // can sneak in from multi-line curl commands or copy-paste issues
    if (typeof questionsRaw === 'string') {
        questionsRaw = questionsRaw.replace(/[\x00-\x1F\x7F]/g, ' ').trim();
    }
    questions = typeof questionsRaw === 'string' ? JSON.parse(questionsRaw) : questionsRaw;
} catch (e) {
    throw new Error('Invalid questions JSON format: ' + e.message);
}

if (!questions || !Array.isArray(questions) || questions.length === 0) {
    throw new Error('Questions must be non-empty array. Got: ' + typeof questions);
}

// Extract domain (optional, can be inferred from questions)
const domain = firstItem.json?.domain || firstItem.json?.body?.domain || firstItem.json?.query?.domain || 'General';

// Calculate file stats using binary metadata + getBinaryDataBuffer as fallback
let totalSize = 0;
const fileMetadata = [];

if (firstItem.binary) {
    for (const [fieldName, binaryData] of Object.entries(firstItem.binary)) {
        if (!binaryData) continue;

        // Get the buffer and generate hash here, since this.helpers.getBinaryDataBuffer 
        // is fully valid for the current node's incoming binary data.
        const buf = await this.helpers.getBinaryDataBuffer(0, fieldName);
        const fileSize = buf.length;
        const hash = crypto.createHash('sha256').update(buf).digest('hex');

        totalSize += fileSize;
        fileMetadata.push({
            fieldName,
            fileName: binaryData.fileName || fieldName,
            fileSize,
            mimeType: binaryData.mimeType || 'application/octet-stream',
            hash
        });
    }
}

// Debug: log binary field names so mismatches are easy to diagnose
console.log('Binary fields available:', JSON.stringify(fileMetadata.map(f => ({ fieldName: f.fieldName, fileName: f.fileName, hash: f.hash }))));

// Enforce 500MB total limit for large file support
if (totalSize > 500 * 1024 * 1024) {
    throw new Error(`Total file size exceeds 500MB limit (current: ${Math.round(totalSize / 1024 / 1024)}MB)`);
}

// Helper: find uploaded file by matching fieldName OR fileName (flexible match)
// Handles n8n field-name sanitization (spaces vs underscores, etc.)
function findUploadedFile(name) {
    const norm = (s) => s.replace(/[_ ]/g, ' ').trim().toLowerCase();
    return fileMetadata.find(f =>
        f.fieldName === name || f.fileName === name ||
        norm(f.fieldName) === norm(name) || norm(f.fileName) === norm(name)
    );
}

// Validate: each question references valid uploaded files
for (const q of questions) {
    if (!q.question_id) {
        throw new Error('Each question must have a "question_id" field');
    }
    if (!q.files || !Array.isArray(q.files) || q.files.length === 0) {
        throw new Error(`Question ${q.question_id} has no files specified`);
    }

    // Remap files array to use the actual binary fieldName for downstream nodes
    q.files = q.files.map(fileName => {
        const found = findUploadedFile(fileName);
        if (!found) {
            const available = fileMetadata.map(f => f.fieldName + ' (file: ' + f.fileName + ')').join(', ');
            throw new Error(`Question ${q.question_id} references file "${fileName}" which was not uploaded. Available: [${available}]`);
        }
        return found.fieldName;
    });
}

// Update JSON content but preserve original binary attachment
firstItem.json = {
    questions,
    domain,
    files: fileMetadata,
    totalSizeMB: Math.round(totalSize / 1024 / 1024 * 100) / 100,
    totalFiles: fileMetadata.length
};

return [firstItem];

