// Calculate hashes and prepare items for writing
const path = require('path');
const fs = require('fs');

const sessionData = $input.first().json;
const sessionId = sessionData.session_id; // from Postgres
// If domain is missing from Postgres, get it from Parse node
const domain = sessionData.domain || $('Parse & Validate Input').first().json.domain;

const prevNodeData = $('Parse & Validate Input').first();
const questions = prevNodeData.json.questions;
const filesMeta = prevNodeData.json.files; // Hashes are now passed here!
const binaryData = prevNodeData.binary;
const binaryKeys = Object.keys(binaryData || {});

// Create session directory
const sessionDir = `/tmp/n8n_processing/${sessionId}`;
if (!fs.existsSync(sessionDir)) {
    fs.mkdirSync(sessionDir, { recursive: true });
}

console.log(`Created session directory: ${sessionDir}`);

const items = [];

for (let ki = 0; ki < binaryKeys.length; ki++) {
    const fieldName = binaryKeys[ki];
    const fileData = binaryData[fieldName];
    if (!fileData) continue;

    // Find the hash computed in the previous step
    const meta = filesMeta.find(f => f.fieldName === fieldName);
    const hash = meta ? meta.hash : 'unknown_hash_' + ki;

    const ext = path.extname(fileData.fileName || '') || '.bin';
    const diskFileName = `${hash}${ext}`;
    const filePath = path.join(sessionDir, diskFileName);

    items.push({
        json: {
            sessionId,
            domain,
            fieldName,
            fileName: fileData.fileName,
            mimeType: fileData.mimeType,
            fileSize: meta ? meta.fileSize : 0,
            hash,
            filePath,
            questions
        },
        // We pass the binary data placeholder forward for Write Binary File to save
        binary: {
            data: fileData
        }
    });
}

return items;

// Reconstruct fileMap and question structure
const items = $input.all();
const firstItem = items[0].json;
const sessionId = firstItem.sessionId;
const domain = firstItem.domain;
const questions = firstItem.questions;

const fileMap = {};

for (const item of items) {
  const row = item.json;
  fileMap[row.fieldName] = {
    hash: row.hash,
    fileName: row.fileName,
    fileSize: row.fileSize,
    mimeType: row.mimeType,
    fieldName: row.fieldName,
    filePath: row.filePath
  };
}

// Map questions to hashes
const questionsWithHashes = questions.map(q => ({
  question_id: q.question_id,
  evidence_files: q.files.map(fileName => {
    const fileInfo = fileMap[fileName];
    return {
      hash: fileInfo.hash,
      originalName: fileInfo.fileName,
      fieldName: fileName
    };
  })
}));

return [{
  json: {
    sessionId,
    domain,
    questions: questionsWithHashes,
    fileMap,
    totalFiles: Object.keys(fileMap).length
  }
}];

// Create Redis job payload
const crypto = require('crypto');

// Get data from Aggregate Files node
const data = $('Aggregate Files').first().json;

// Debug: log what we received
console.log('Build Redis Job - received data keys:', Object.keys(data));
console.log('Build Redis Job - questions value:', data.questions);

if (!data.questions || !Array.isArray(data.questions)) {
  throw new Error('Invalid data received: questions is ' + typeof data.questions + '. Full data keys: ' + Object.keys(data).join(', '));
}

const jobId = crypto.randomUUID();

const job = {
  jobId: jobId,
  sessionId: data.sessionId,
  domain: data.domain,
  questions: data.questions,
  fileMap: data.fileMap,
  sessionDir: `/tmp/n8n_processing/${data.sessionId}`,
  status: 'queued',
  createdAt: new Date().toISOString()
};

return [{
  json: {
    jobData: JSON.stringify(job),
    jobId: jobId,
    sessionId: data.sessionId,
    totalQuestions: data.questions.length
  }
}];

